import{c as a,cG as i,cb as s,c8 as e,cf as l,cT as t,ce as n}from"./chunks/framework.BlkIsu1j.js";const r=JSON.parse('{"title":"核心功能","description":"","frontmatter":{"title":"核心功能","outline":"deep","layout":"doc","prev":"/ai/claudecode/02-how-it-works","next":"/ai/claudecode/04-ecosystem","date":"2026-05-20T10:00:00.000Z"},"headers":[],"relativePath":"ai/claudecode/03-core-features.md","filePath":"ai/claudecode/03-core-features.md","lastUpdated":1779211503000}'),h={id:"frontmatter-title",tabindex:"-1"};const o=a({name:"ai/claudecode/03-core-features.md"},[["render",function(a,r,o,d,p,k){return i(),s("div",null,[e("h1",h,[l(t(a.$frontmatter.title)+" ",1),r[0]||(r[0]=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),r[1]||(r[1]=n('<p>本章按从简单到复杂的顺序，逐一介绍 Claude Code 的核心功能。每个功能都包含 <strong>功能说明</strong>、<strong>实战演练</strong> 和 <strong>最佳实践</strong>。</p><h2 id="_3-1-基础对话与代码理解" tabindex="-1">3.1 基础对话与代码理解 <a class="header-anchor" href="#_3-1-基础对话与代码理解" aria-label="Permalink to “3.1 基础对话与代码理解”">​</a></h2><h3 id="功能说明" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明" aria-label="Permalink to “功能说明”">​</a></h3><p>这是 Claude Code 最基础的使用方式：向它提问，让它在你的项目中寻找答案。Claude Code 会自动读取项目文件来理解上下文。</p><h3 id="实战演练" tabindex="-1">实战演练 <a class="header-anchor" href="#实战演练" aria-label="Permalink to “实战演练”">​</a></h3><p><strong>场景</strong>：你接手了一个陌生项目，需要快速理解它。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>这个项目是做什么的？主要用了哪些技术栈？</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>src/backend/ 目录下的认证逻辑是怎么实现的？帮我梳理一下流程。</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>这个 Dockerfile 做了什么优化？有没有可以改进的地方？</span></span></code></pre></div><h3 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to “最佳实践”">​</a></h3><ul><li><strong>把 Claude Code 当新人同事来带</strong>：给它足够上下文，不要假设它已经知道</li><li><strong>使用 <code>/clear</code> 开启新话题</strong>：避免旧对话干扰新问题</li><li><strong>指定文件范围</strong>：&quot;只看 src/api/ 目录&quot; 比 &quot;看看代码&quot; 更精准</li><li><strong>要求它先读再答</strong>：&quot;先读取相关文件再回答&quot; 确保它的回答基于实际代码</li></ul><h2 id="_3-2-代码编辑与重构" tabindex="-1">3.2 代码编辑与重构 <a class="header-anchor" href="#_3-2-代码编辑与重构" aria-label="Permalink to “3.2 代码编辑与重构”">​</a></h2><h3 id="功能说明-1" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明-1" aria-label="Permalink to “功能说明”">​</a></h3><p>Claude Code 通过 <code>Edit</code> 和 <code>Write</code> 工具直接修改你的文件。你可以看到精确的 Diff 对比，选择接受或拒绝每个变更。</p><h3 id="实战演练-1" tabindex="-1">实战演练 <a class="header-anchor" href="#实战演练-1" aria-label="Permalink to “实战演练”">​</a></h3><p><strong>场景 1：提取公共函数</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>src/components/ 里有三个组件都写了相似的日期格式化逻辑，请帮我提取成一个公共工具函数。</span></span></code></pre></div><p>Claude Code 会：</p><ol><li>读取三个组件文件</li><li>识别重复逻辑</li><li>创建 <code>src/utils/formatDate.ts</code></li><li>修改三个组件文件，替换为公共函数导入</li></ol><p><strong>场景 2：批量重命名</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>把项目中所有用到 getUser 的地方改成 fetchUser，包括函数定义、调用和导入语句。</span></span></code></pre></div><h3 id="最佳实践-1" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践-1" aria-label="Permalink to “最佳实践”">​</a></h3><ul><li><strong>小步快跑</strong>：一次做一件事，不要在一个指令中塞入太多变更</li><li><strong>先读后改</strong>：让 Claude 先展示它打算改什么，确认后再让它动手</li><li><strong>变更后立即验证</strong>：改完一个模块就运行测试，不要等到改完所有文件</li><li><strong>使用 Git</strong>：每次满意后提交，不满意可以随时回退</li></ul><h2 id="_3-3-终端命令执行" tabindex="-1">3.3 终端命令执行 <a class="header-anchor" href="#_3-3-终端命令执行" aria-label="Permalink to “3.3 终端命令执行”">​</a></h2><h3 id="功能说明-2" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明-2" aria-label="Permalink to “功能说明”">​</a></h3><p>Claude Code 可以直接在你的终端中执行命令——运行构建、安装依赖、执行测试——并读取输出来判断结果。</p><h3 id="实战演练-2" tabindex="-1">实战演练 <a class="header-anchor" href="#实战演练-2" aria-label="Permalink to “实战演练”">​</a></h3><p><strong>场景 1：调试构建失败</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>项目 build 失败了，帮我找出原因并修复。</span></span></code></pre></div><p>Claude Code 会：</p><ol><li>执行 <code>pnpm build</code>（或项目的构建命令）</li><li>读取错误输出</li><li>找到出错的文件，分析原因</li><li>提出修复方案</li><li>修改代码后重新构建验证</li></ol><p><strong>场景 2：依赖问题排查</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>npm install 报了一堆 peer dependency 警告，帮我分析哪些需要处理。</span></span></code></pre></div><h3 id="最佳实践-2" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践-2" aria-label="Permalink to “最佳实践”">​</a></h3><ul><li><strong>危险命令需要确认</strong>：<code>rm -rf</code>、<code>git push --force</code> 等操作会弹出确认弹窗，仔细审查</li><li><strong>配置权限白名单</strong>：把你信任的常用命令（如 <code>npm test</code>）加入 allowlist，减少确认次数</li><li><strong>让 Claude 解释命令</strong>：如果它要执行你不理解的命令，问一句 &quot;这个命令做了什么？&quot;</li></ul><h2 id="_3-4-git-操作" tabindex="-1">3.4 Git 操作 <a class="header-anchor" href="#_3-4-git-操作" aria-label="Permalink to “3.4 Git 操作”">​</a></h2><h3 id="功能说明-3" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明-3" aria-label="Permalink to “功能说明”">​</a></h3><p>Claude Code 可以执行完整的 Git 工作流：查看状态、创建分支、暂存文件、创建提交、甚至创建 PR。</p><h3 id="实战演练-3" tabindex="-1">实战演练 <a class="header-anchor" href="#实战演练-3" aria-label="Permalink to “实战演练”">​</a></h3><p><strong>场景：自动提交</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>我改完了，帮我看看改了什么，然后创建一个合适的提交。</span></span></code></pre></div><p>Claude Code 会：</p><ol><li>执行 <code>git status</code> 和 <code>git diff</code></li><li>分析变更内容</li><li>起草一条符合规范的 commit message</li><li>暂存文件并创建提交</li></ol><h3 id="最佳实践-3" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践-3" aria-label="Permalink to “最佳实践”">​</a></h3><ul><li><strong>永远让 Claude 先展示计划再提交</strong>：在它执行 <code>git commit</code> 前确认 commit message</li><li><strong>设定提交规范</strong>：在 CLAUDE.md 中写明你的 commit message 格式要求</li><li><strong>不要跳过 hooks</strong>：Git hooks 存在是有原因的，不要让它用 <code>--no-verify</code></li></ul><h2 id="_3-5-项目级多文件编辑" tabindex="-1">3.5 项目级多文件编辑 <a class="header-anchor" href="#_3-5-项目级多文件编辑" aria-label="Permalink to “3.5 项目级多文件编辑”">​</a></h2><h3 id="功能说明-4" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明-4" aria-label="Permalink to “功能说明”">​</a></h3><p>当任务涉及 5+ 个文件时，Claude Code 会自动使用 <code>TodoWrite</code> 跟踪进度，逐个文件处理，最后汇总。</p><h3 id="实战演练-4" tabindex="-1">实战演练 <a class="header-anchor" href="#实战演练-4" aria-label="Permalink to “实战演练”">​</a></h3><p><strong>场景：添加一个新 API 端点</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我加一个新的 GET /api/users/:id/profile 端点。需要：新增路由、controller、service 层逻辑、数据库查询、以及对应的类型定义。</span></span></code></pre></div><p>Claude Code 会：</p><ol><li>分析现有路由和 controller 的模式</li><li>创建 TodoWrite 任务列表</li><li>按数据库层 → Service → Controller → 路由的顺序依次实现</li><li>每完成一步验证一致性</li></ol><h3 id="最佳实践-4" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践-4" aria-label="Permalink to “最佳实践”">​</a></h3><ul><li><strong>描述最终目标，而非具体步骤</strong>：让 Claude Code 自己规划执行顺序</li><li><strong>复杂任务使用 Plan Mode</strong>：先让它出计划，审查后再执行</li><li><strong>分阶段审查</strong>：每完成一个模块就停下来看看，不要让它一口气改 20 个文件</li></ul><h2 id="_3-6-plan-mode-计划模式" tabindex="-1">3.6 Plan Mode（计划模式） <a class="header-anchor" href="#_3-6-plan-mode-计划模式" aria-label="Permalink to “3.6 Plan Mode（计划模式）”">​</a></h2><h3 id="功能说明-5" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明-5" aria-label="Permalink to “功能说明”">​</a></h3><p>Plan Mode 是 Claude Code 的重要功能。在写代码前，Claude 会先<strong>探索项目、设计方案、让你审查</strong>，然后再动手实现。</p><h3 id="实战演练-5" tabindex="-1">实战演练 <a class="header-anchor" href="#实战演练-5" aria-label="Permalink to “实战演练”">​</a></h3><p><strong>场景：大型功能设计</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我设计一个用户通知系统，支持站内信和邮件通知。</span></span></code></pre></div><p>进入 Plan Mode 后，Claude Code 会：</p><ol><li>探索项目现有架构</li><li>提出 2-3 种设计方案</li><li>列出每种方案的利弊</li><li>等待你确认后再生成详细实现计划</li><li>计划批准后才开始写代码</li></ol><h3 id="最佳实践-5" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践-5" aria-label="Permalink to “最佳实践”">​</a></h3><ul><li><strong>涉及 3+ 文件的变更，默认开启 Plan Mode</strong>：减少返工</li><li><strong>在计划阶段多提意见</strong>：这是调整方向成本最低的时候</li><li><strong>复杂项目始终用 Plan Mode</strong>：简单修复可以跳过</li></ul><h2 id="_3-7-skills-技能系统" tabindex="-1">3.7 Skills 技能系统 <a class="header-anchor" href="#_3-7-skills-技能系统" aria-label="Permalink to “3.7 Skills 技能系统”">​</a></h2><h3 id="功能说明-6" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明-6" aria-label="Permalink to “功能说明”">​</a></h3><p>Skills 是 Claude Code 的可复用能力模块。每个 Skill 封装了一套领域知识和工作流程。Skills 由社区或团队维护，按需加载。</p><h3 id="实战演练-6" tabindex="-1">实战演练 <a class="header-anchor" href="#实战演练-6" aria-label="Permalink to “实战演练”">​</a></h3><p><strong>场景：使用 brainstorming skill 设计新功能</strong></p><p>当你描述一个创意需求时，Claude Code 会自动检测到相关 Skill 并激活。例如说 &quot;我想加一个暗色模式&quot;，brainstorming skill 会被激活，引导你完成需求分析。</p><p>或者手动激活：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/superpowers:brainstorming</span></span>\n<span class="line"><span>我想在项目中加入实时通知功能。</span></span></code></pre></div><h3 id="最佳实践-6" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践-6" aria-label="Permalink to “最佳实践”">​</a></h3><ul><li><strong>了解你常用的 Skills</strong>：知道哪些场景有对应的 Skill 可以用</li><li><strong>尊重 Skill 的工作流程</strong>：Skill 有自己的流程设计，不要跳过步骤</li><li><strong>可以编写自己的 Skills</strong>：团队可以封装内部最佳实践为 Skills</li></ul><h2 id="_3-8-hooks-钩子系统" tabindex="-1">3.8 Hooks 钩子系统 <a class="header-anchor" href="#_3-8-hooks-钩子系统" aria-label="Permalink to “3.8 Hooks 钩子系统”">​</a></h2><h3 id="功能说明-7" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明-7" aria-label="Permalink to “功能说明”">​</a></h3><p>Hooks 允许你在 Claude Code 的特定生命周期节点（如工具调用前/后、会话启动/结束）插入自定义逻辑。</p><h3 id="实战演练-7" tabindex="-1">实战演练 <a class="header-anchor" href="#实战演练-7" aria-label="Permalink to “实战演练”">​</a></h3><p><strong>场景：自动运行 lint</strong></p><p>配置一个 Hook，在 Claude Code 写文件后自动运行 ESLint：</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// .claude/settings.json</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;hooks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;PostToolUse&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;matcher&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Edit|Write&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pnpm lint --fix ${CLAUDE_TOOL_OUTPUT_FILE}&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="最佳实践-7" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践-7" aria-label="Permalink to “最佳实践”">​</a></h3><ul><li><strong>用 Hooks 保证代码质量</strong>：自动 lint、自动格式化</li><li><strong>不要过度使用</strong>：每个 Hook 都会增加延迟</li><li><strong>PreToolUse 用于额外验证</strong>：PostToolUse 用于自动化清理</li></ul><h2 id="_3-9-mcp-扩展" tabindex="-1">3.9 MCP 扩展 <a class="header-anchor" href="#_3-9-mcp-扩展" aria-label="Permalink to “3.9 MCP 扩展”">​</a></h2><h3 id="功能说明-8" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明-8" aria-label="Permalink to “功能说明”">​</a></h3><p>MCP（Model Context Protocol）是 Anthropic 提出的开放协议，允许 Claude Code 连接外部工具和数据源。你可以通过 MCP Server 让 Claude Code 访问数据库、调用 API、查询文档等。</p><h3 id="实战演练-8" tabindex="-1">实战演练 <a class="header-anchor" href="#实战演练-8" aria-label="Permalink to “实战演练”">​</a></h3><p><strong>场景：连接 GitHub</strong></p><p>配置 GitHub MCP Server 后，Claude Code 可以直接操作 Issues、PR、Actions：</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// .claude/mcp.json</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;github&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-y&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@anthropic/mcp-server-github&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;env&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;GITHUB_TOKEN&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;${env:GITHUB_TOKEN}&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>然后直接在对话中说：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我看看这个项目有多少个 open issues，有哪些是 bug？</span></span></code></pre></div><h3 id="最佳实践-8" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践-8" aria-label="Permalink to “最佳实践”">​</a></h3><ul><li><strong>从官方 MCP Server 开始</strong>：GitHub、Postgres、Slack 等都有官方支持</li><li><strong>一个 MCP Server 一个职责</strong>：不要在一个 Server 中混合多种功能</li><li><strong>注意安全性</strong>：MCP Server 能做的事 Claude 都能做，给予权限要审慎</li></ul><h2 id="_3-10-sub-agent-子代理" tabindex="-1">3.10 Sub-agent（子代理） <a class="header-anchor" href="#_3-10-sub-agent-子代理" aria-label="Permalink to “3.10 Sub-agent（子代理）”">​</a></h2><h3 id="功能说明-9" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明-9" aria-label="Permalink to “功能说明”">​</a></h3><p>当任务可以拆分为多个独立子任务时，Claude Code 可以启动 Sub-agent 并行执行。每个 Sub-agent 是独立的 Claude 实例，有自己的上下文窗口。</p><h3 id="实战演练-9" tabindex="-1">实战演练 <a class="header-anchor" href="#实战演练-9" aria-label="Permalink to “实战演练”">​</a></h3><p><strong>场景：并行代码审查</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我对 src/utils/、src/components/、src/hooks/ 三个目录分别做代码审查。</span></span></code></pre></div><p>Claude Code 会启动 3 个并行的 Sub-agent，各自审查一个目录，最后汇总结果。</p><h3 id="最佳实践-9" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践-9" aria-label="Permalink to “最佳实践”">​</a></h3><ul><li><strong>适用于无依赖的并行任务</strong>：各自改不同文件、分别审查不同模块</li><li><strong>不适用于有依赖的任务</strong>：如果任务 B 依赖任务 A 的结果，不要并行化</li><li><strong>子代理的上下文是独立的</strong>：不要把全局信息放在子代理提示里</li></ul><h2 id="_3-11-memory-持久化记忆" tabindex="-1">3.11 Memory（持久化记忆） <a class="header-anchor" href="#_3-11-memory-持久化记忆" aria-label="Permalink to “3.11 Memory（持久化记忆）”">​</a></h2><h3 id="功能说明-10" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明-10" aria-label="Permalink to “功能说明”">​</a></h3><p>Claude Code 的 Memory 系统会在项目目录下存储关键信息，跨会话保持。它可以记住：</p><ul><li>你的技术偏好和常用工具</li><li>项目的当前状态和进行中的工作</li><li>你之前的反馈和纠正</li></ul><h3 id="实战演练-10" tabindex="-1">实战演练 <a class="header-anchor" href="#实战演练-10" aria-label="Permalink to “实战演练”">​</a></h3><p>Memory 是自动工作的。当你说：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>这个项目的测试必须用 vitest，不要用 jest。</span></span></code></pre></div><p>Claude Code 会自动将这条规则存入 Memory。下次你让它写测试时，它会自动使用 vitest。</p><h3 id="最佳实践-10" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践-10" aria-label="Permalink to “最佳实践”">​</a></h3><ul><li><strong>明确告知偏好</strong>：&quot;以后做 X 时永远用 Y 方式&quot;——这种声明会被记录</li><li><strong>纠正错误时给出原因</strong>：&quot;不要用 X，因为 Y&quot;——带原因的反馈更容易被泛化</li><li><strong>定期清理</strong>：过时的 Memory 可以用 <code>/memory</code> 命令管理</li></ul>',114))])}]]);export{r as __pageData,o as default};
